  const normalized = (value || '').trim();
  if (!normalized) return '';
  if (/^[^/\s]+\/[^/\s]+$/.test(normalized)) return normalized.replace(/\.git$/i, '');
  const m = normalized.match(/github\.com[/:]([^/\s]+)\/([^/.\s]+)(?:\.git)?/i);
  return m ? `${m[1]}/${m[2]}` : '';
